UPDATE tours SET translations = '{"ko":{"title":"부산 출발 경주 유네스코 레거시 투어 (국립박물관 포함)","description":"아홉산숲(400년 대나무 숲)을 시작으로 불국사(유네스코 세계문화유산), 국립경주박물관(신라 유물 30만 점), 교촌한옥마을(경주 최씨 고택), 월정교(통일신라 760년 목교 복원)까지 경주 핵심을 소그룹으로 하루에 돌아봅니다.","badges":["유네스코","국립박물관 포함","소그룹","부산 출발"],"duration":"11.5 hours"},"ja":{"title":"釜山→慶州UNESCO遺産ツアー：寺院・博物館・橋","description":"釜山から日帰りで韓国千年の古都・慶州を巡る少人数ツアー：アホプサン竹林→仏国寺（UNESCO世界遺産）→慶州国立博物館→校村韓屋村→月精橋（夜間ライトアップ）。UNESCO遺産・考古学・建築・韓国の「遺産テーマ」を一日で濃縮体験。","badges":["少人数","慶州","UNESCO","仏国寺","釜山発"],"duration":"11.5時間"},"zh":{"title":"釜山出发庆州UNESCO遗产一日游（含国立博物馆）","description":"Small-group day tour from Busan to Gyeongju, the Silla kingdom''s capital for 992 years (57 BCE–935 CE) and the densest concentration of UNESCO World Heritage sites in Korea. Route: Ahopsan Bamboo Forest → Bulguksa Temple (UNESCO) → Gyeongju ssambap lunch → Gyeongju National Museum → Gyochon Hanok Village → Woljeonggyo Bridge. English/Chinese-speaking certified guide; mini-van; admissions to Bulguksa and the museum are free.","badges":["世界遗产","含国立博物馆","小团体","釜山出发"],"duration":"11.5 hours"},"zh-TW":{"title":"釜山出發慶州UNESCO遺產一日遊（含國立博物館）","description":"Small-group day tour from Busan to Gyeongju, the Silla kingdom''s capital for 992 years (57 BCE–935 CE) and the densest concentration of UNESCO World Heritage sites in Korea. Route: Ahopsan Bamboo Forest → Bulguksa Temple (UNESCO) → Gyeongju ssambap lunch → Gyeongju National Museum → Gyochon Hanok Village → Woljeonggyo Bridge. English/Chinese-speaking certified guide; mini-van; admissions to Bulguksa and the museum are free.","badges":["世界遺產","含國立博物館","小團體","釜山出發"],"duration":"11.5 hours"},"es":{"title":"Tour Busan→Gyeongju: Bulguksa, Museo Nacional de Silla y Puente Woljeonggyo","description":"La capital milenaria de la antigua Silla en un día desde Busan: Bosque de Bambú Ahopsan (gestionado 400 años por el Clan Moon) → Templo Bulguksa (Patrimonio UNESCO, coronas de oro y pagodas únicas) → almuerzo en Gyeongju → Museo Nacional de Gyeongju (corona de oro Silla + Campana del Gran Rey Seongdeok) → Aldea Hanok Gyochon → Puente Woljeonggyo al atardecer. Incluye el Museo Nacional. Grupo pequeño (~10 pasajeros).","badges":["UNESCO","Incluye Museo Nacional","Grupo pequeño","Desde Busan"],"duration":"Un día (desde Busan)"}}'::jsonb, updated_at = NOW() WHERE slug = 'busan-gyeongju-unesco-legacy-tour-national-museum';
UPDATE tours SET translations = '{"ko":{"title":"부산 출발 매화·벚꽃 투어 · 양산+경주","description":"통도사(유네스코 산사, 350년 자장매), 불국사(유네스코 세계문화유산), 보문호(경주 대표 벚꽃 명소)를 하루에 잇는 봄 시즌 한정 투어. 소그룹 밴, 공인 가이드.","badges":["봄 시즌 한정","매화+벚꽃","유네스코 명소 2곳","부산 픽업"],"duration":"8.5 hours"},"ja":{"title":"釜山：梅・桜ツアー 梁山＋慶州","description":"梅と桜の両方をカバーする釜山発の春限定8.5時間ツアー — 通度寺（UNESCO山寺＋350年の慈蔵梅）→ウォンドン水芹サムギョプサル昼食（梅シーズン）→仏国寺（UNESCO世界遺産）→鰲渓浦湖（桜）。2月25日〜4月10日のみ運営。","badges":["少人数","釜山発","梅桜ツアー","UNESCO","春限定"],"duration":"8.5時間"},"zh":{"title":"釜山出发梁山＋庆州梅花＆樱花双季一日游","description":"An 8.5-hour Busan-departure dual-season shuttle covering Yangsan and Gyeongju. The default itinerary visits Tongdosa Temple (UNESCO Sansa, Korea''s Three Jewel Temple, with the 350-year Jajangmae plum tree), Wondong Plum Blossom Village (Minari Samgyeopsal lunch in greenhouse pop-up restaurants), Bulguksa Temple (UNESCO World Heritage), and Bomun Lake (8 km cherry blossom loop). Wider operating window than cherry-only tours: ~Feb 25 – Apr 10 covers both plum and cherry blossom peaks. Daily route shifts emphasis based on plum vs cherry bloom status.","badges":["春季限定","梅花＋樱花","2处世界遗产","釜山接送"],"duration":"8.5 hours"},"zh-TW":{"title":"釜山出發梁山＋慶州梅花＆櫻花雙季一日遊","description":"An 8.5-hour Busan-departure dual-season shuttle covering Yangsan and Gyeongju. The default itinerary visits Tongdosa Temple (UNESCO Sansa, Korea''s Three Jewel Temple, with the 350-year Jajangmae plum tree), Wondong Plum Blossom Village (Minari Samgyeopsal lunch in greenhouse pop-up restaurants), Bulguksa Temple (UNESCO World Heritage), and Bomun Lake (8 km cherry blossom loop). Wider operating window than cherry-only tours: ~Feb 25 – Apr 10 covers both plum and cherry blossom peaks. Daily route shifts emphasis based on plum vs cherry bloom status.","badges":["春季限定","梅花＋櫻花","2處世界遺產","釜山接送"],"duration":"8.5 hours"},"es":{"title":"Tour Primavera Busan: Ciruelos de Tongdosa y Cerezos de Gyeongju","description":"Temporada de ciruelos y cerezos desde Busan (25 feb – 10 abr): Templo Tongdosa en Yangsan (UNESCO + ciruelo Jajangmae de 350 años) → almuerzo minari-samgyeopsal (temporada de ciruelos) o local de Gyeongju (temporada de cerezos) → Templo Bulguksa (UNESCO 1995) → Lago Bomun (9.000 cerezos). Dos Patrimonios UNESCO y dos floraciones en un único shuttle de 8,5 horas.","badges":["Solo primavera","Ciruelos + cerezos","2 sitios UNESCO","Desde Busan"],"duration":"8,5 horas (solo 25 feb – 10 abr)"}}'::jsonb, updated_at = NOW() WHERE slug = 'busan-plum-cherry-blossom-day-tour-to-yangsan-gyeongju';
UPDATE tours SET translations = '{"ko":{"title":"부산 프라이빗 크루즈 기항지 전세 투어","description":"프라이빗 전세 차량으로 유엔기념공원, 태종대, 감천문화마을, 용두산공원·부산타워, 자갈치시장을 돌아보는 완전 맞춤형 부산 크루즈 기항지 투어입니다. 귀선 보장.","badges":["프라이빗 전세 투어","코스 맞춤 가능","크루즈 터미널 픽업 포함"],"duration":"8 hours"},"ja":{"title":"釜山プライベートクルーズ寄港地カーチャーター（8時間カスタム）","description":"釜山港着岸のクルーズ乗客向け8時間プライベートカーチャーター。認定ドライバーガイド付きで、国連記念公園→太宗台断崖→甘川文化村→龍頭山公園→チャガルチ水産市場を巡る標準ルートを基本に、スポットのカスタマイズも可能。帰船時間を最優先に設計された専用車サービス。","badges":["クルーズ寄港地","釜山","プライベート","カスタム","港発着"],"duration":"8時間（カスタム）"},"zh":{"title":"釜山邮轮岸上私人包车一日游","description":"An 8-hour private car charter for Busan cruise passengers with a licensed English-speaking driver-guide. Default itinerary covers UN Memorial Cemetery, Taejongdae cliffs, Gamcheon Culture Village, Yongdusan Park, and Jagalchi Market. Fully customizable. Pickup at the cruise terminal, KTX station, or any central Busan hotel; on-time return to the ship is guaranteed.","badges":["私人包车游","路线可自订","邮轮码头接送含括"],"duration":"8 hours"},"zh-TW":{"title":"釜山郵輪岸上私人包車一日遊","description":"An 8-hour private car charter for Busan cruise passengers with a licensed English-speaking driver-guide. Default itinerary covers UN Memorial Cemetery, Taejongdae cliffs, Gamcheon Culture Village, Yongdusan Park, and Jagalchi Market. Fully customizable. Pickup at the cruise terminal, KTX station, or any central Busan hotel; on-time return to the ship is guaranteed.","badges":["私人包車遊","路線可自訂","郵輪碼頭接送含括"],"duration":"8 hours"},"es":{"title":"Busan Private Car Charter for Cruise Shore","description":"Excursión en escala de crucero por Busan en coche privado con guía-conductor certificado (8 horas): recogida en el terminal → Memorial ONU → Taejongdae → almuerzo → Villa Gamcheon → Torre de Busan → Mercado Jagalchi → regreso al terminal. Itinerario personalizable. Regreso garantizado 90-120 min antes de la salida.","badges":["Private Tour","Customizable Route","Cruise Pickup Included"],"duration":"8 hours"}}'::jsonb, updated_at = NOW() WHERE slug = 'busan-private-car-charter-cruise-shore';
UPDATE tours SET translations = '{"ko":{"title":"부산 크루즈 기항지 소그룹 관광 (합승 밴, 9시간)","description":"유엔기념공원(세계 유일 유엔 군인 묘지), 태종대(부산 남단 해안 절벽 공원), 감천문화마을(부산의 마추픽추), 용두산공원·부산타워, 자갈치수산시장까지 크루즈 기항지 시간에 맞춘 소그룹 투어입니다. 귀선 시각 60분 전 터미널 귀환 보장.","badges":["크루즈 기항 일일 투어","소형 합승 밴","항구 픽업","9시간 서비스 창"],"duration":"9 hours"},"ja":{"title":"釜山クルーズ寄港地観光・少人数9時間","description":"釜山港発着のクルーズ寄港地少人数観光ツアー9時間：国連記念公園（世界唯一の国連記念墓地）→太宗台海岸断崖→甘川文化村（韓国のサントリーニ）→龍頭山公園＆釜山タワー→チャガルチ水産市場。昼食込み、帰船時間を厳守。","badges":["クルーズ寄港地","釜山","少人数","昼食込み","港発着"],"duration":"9時間"},"zh":{"title":"釜山邮轮岸上观光小团体一日游","description":"Shared-van day tour from the Busan cruise terminal hitting the city''s five most-asked-for stops in a single 9-hour window: UN Memorial Cemetery (Korean War context), Taejongdae coastal cliffs, lunch at a local Busan restaurant, Gamcheon Culture Village (the painted hillside), Yongdusan Park with optional Busan Tower observatory, and Jagalchi Market. Pickup calibrated to your specific ship''s disembarkation. Certified English/Chinese-speaking guide.","badges":["邮轮停靠一日游","共乘小型厢型车","港口接送","9小时行程"],"duration":"9 hours"},"zh-TW":{"title":"釜山郵輪岸上觀光小團體一日遊","description":"Shared-van day tour from the Busan cruise terminal hitting the city''s five most-asked-for stops in a single 9-hour window: UN Memorial Cemetery (Korean War context), Taejongdae coastal cliffs, lunch at a local Busan restaurant, Gamcheon Culture Village (the painted hillside), Yongdusan Park with optional Busan Tower observatory, and Jagalchi Market. Pickup calibrated to your specific ship''s disembarkation. Certified English/Chinese-speaking guide.","badges":["郵輪停靠一日遊","共乘小型廂型車","港口接送","9小時行程"],"duration":"9 hours"},"es":{"title":"Excursión en Escala de Crucero por Busan — Furgoneta Compartida (9 horas)","description":"Cinco hitos de Busan desde el terminal de cruceros en una furgoneta compartida de grupo pequeño (9 horas): Memorial de la ONU de Corea (el único en el mundo) → Taejongdae (acantilados costeros al sur de la isla Yeongdo) → almuerzo incluido → Villa Cultural Gamcheon (Machu Picchu coreano) → Yongdusan Park y Torre de Busan → Mercado Jagalchi y Nampo-dong → regreso al puerto. Almuerzo incluido.","badges":["Escala de crucero","Furgoneta compartida","Recogida en el puerto","Ventana de 9 horas"],"duration":"9 horas (barco → barco)"}}'::jsonb, updated_at = NOW() WHERE slug = 'busan-small-group-sightseeing-tour-cruise-passengers';
UPDATE tours SET translations = '{"ko":{"title":"부산 출발 경주 봄 벚꽃 소그룹 일일 투어","description":"보문호(경주 대표 벚꽃 명소), 첨성대+대릉원(유네스코 경주 역사지구), 불국사(유네스코)를 봄 시즌 한정(3/28~4/10)으로 소그룹 투어. 공인 가이드.","badges":["봄 시즌 한정","벚꽃 투어","유네스코 명소","부산 픽업"],"duration":"8.5 hours"},"ja":{"title":"釜山→慶州桜ハイライトツアー","description":"釜山発の慶州桜ハイライト8.5時間ツアー（3月28日〜4月10日限定）：鰲渓浦湖（慶州最大の桜）→瞻星台＋大陵苑（UNESCO）→慶州地元料理の昼食→仏国寺（UNESCO）。3大桜スポット、全入場料無料。","badges":["少人数","釜山発","桜ツアー","UNESCO","春限定"],"duration":"8.5時間"},"zh":{"title":"釜山出发庆州春季赏樱一日游","description":"An 8.5-hour Busan-departure shuttle tour to Gyeongju''s biggest spring cherry blossom spots. The default route covers Bomun Lake (8 km of cherry tree-lined lakeside walking), the Cheomseongdae + Daereungwon historic core (UNESCO Gyeongju Historic Areas), and Bulguksa Temple (UNESCO World Heritage with mid-April yaezakura double cherry blossom). 2–3 stops are confirmed each morning based on the day''s bloom report. Tour operates Mar 28 to Apr 10 only — full refund if bloom is materially delayed or finished.","badges":["春季限定","赏樱之旅","世界遗产景点","釜山接送"],"duration":"8.5 hours"},"zh-TW":{"title":"釜山出發慶州春季賞櫻一日遊","description":"An 8.5-hour Busan-departure shuttle tour to Gyeongju''s biggest spring cherry blossom spots. The default route covers Bomun Lake (8 km of cherry tree-lined lakeside walking), the Cheomseongdae + Daereungwon historic core (UNESCO Gyeongju Historic Areas), and Bulguksa Temple (UNESCO World Heritage with mid-April yaezakura double cherry blossom). 2–3 stops are confirmed each morning based on the day''s bloom report. Tour operates Mar 28 to Apr 10 only — full refund if bloom is materially delayed or finished.","badges":["春季限定","賞櫻之旅","世界遺產景點","釜山接送"],"duration":"8.5 hours"},"es":{"title":"Tour Flor de Cerezo Busan→Gyeongju: Lago Bomun, Cheomseongdae y Bulguksa","description":"El tour de cerezos más completo de Gyeongju desde Busan (28 mar – 10 abr): Lago Bomun (9.000 cerezos, reflejo en el agua) → Cheomseongdae (el observatorio astronómico más antiguo de Asia) + Daereungwon (tumba Silla UNESCO 2000) → almuerzo local → Templo Bulguksa (UNESCO 1995, cerezos tardíos en la avenida). 8,5 horas, dos Patrimonios UNESCO, guía bilingüe.","badges":["Solo primavera","Tour de cerezos","Patrimonio UNESCO","Desde Busan"],"duration":"8,5 horas (solo 28 mar – 10 abr)"}}'::jsonb, updated_at = NOW() WHERE slug = 'busan-spring-cherry-blossom-gyeongju-highlights-day-tour';
UPDATE tours SET translations = '{"ko":{"title":"부산 핵심 명소 7곳 소그룹 일일 투어","description":"해동용궁사(절벽 위 사찰), 청사포·블루라인파크(해안 레일), 유엔기념공원(유일한 유엔 묘지), 감천문화마을(부산의 마추픽추), 자갈치수산시장(한국 최대 수산시장)까지 부산 7대 명소를 소그룹으로 하루에 돌아봅니다. 전 입장료 무료, 공인 가이드.","badges":["소그룹","첫 방문 추천","부산 클래식 코스","연중 운행"],"duration":"10.5 hours"},"ja":{"title":"釜山トップ観光地少人数日帰りツアー","description":"釜山の7大スポットをバランスよく一日で巡る少人数ツアー：海東龍宮寺（韓国一有名な海岸仏教寺院）・青沙浦ブルーラインパーク（廃線路の海岸観光列車）・国連記念公園（世界唯一の国連記念墓地）・甘川文化村（韓国のサントリーニ）・チャガルチ水産市場。3か所のピックアップポイント。","badges":["少人数","釜山","海岸寺院","文化村","水産市場"],"duration":"10.5時間"},"zh":{"title":"釜山精华景点小团体一日游","description":"Single-day, 7-stop small-group tour covering Busan''s classic circuit: Haedong Yonggungsa seaside temple, Cheongsapo & Blue Line Park (optional Sky Capsule), local Busan lunch, UN Memorial Cemetery, Gamcheon Culture Village''s painted hillside, and Jagalchi Fish Market. Three pickup points across central Busan; certified English-speaking guide; mini-coach (≈12 max). All site admissions are free; only lunch and optional tickets are paid on-day.","badges":["小团体","初访友善","釜山经典路线","全年开团"],"duration":"10.5 hours"},"zh-TW":{"title":"釜山精華景點小團體一日遊","description":"Single-day, 7-stop small-group tour covering Busan''s classic circuit: Haedong Yonggungsa seaside temple, Cheongsapo & Blue Line Park (optional Sky Capsule), local Busan lunch, UN Memorial Cemetery, Gamcheon Culture Village''s painted hillside, and Jagalchi Fish Market. Three pickup points across central Busan; certified English-speaking guide; mini-coach (≈12 max). All site admissions are free; only lunch and optional tickets are paid on-day.","badges":["小團體","初訪友善","釜山經典路線","全年開團"],"duration":"10.5 hours"},"es":{"title":"Tour Busan: 7 Hitos en un Día — Templo, Costa, Memorial y Mercado","description":"El circuito clásico de Busan en un día equilibrado: Templo Haedong Yonggungsa (el único templo budista coreano frente al mar) → Blue Line Park de Haeundae (tren costero sobre vías en desuso) → Memorial de la ONU de Corea (el único cementerio memorial de la ONU en el mundo) → Villa Cultural Gamcheon (''Machu Picchu de Corea'') → Mercado Jagalchi (el mayor mercado de mariscos de Corea). Grupo pequeño, todas las entradas gratuitas, sin paradas de compras.","badges":["Grupo pequeño","Primera visita a Busan","Clásico de Busan","Todo el año"],"duration":"Un día"}}'::jsonb, updated_at = NOW() WHERE slug = 'busan-top-attractions-day-tour';
UPDATE tours SET translations = '{"ko":{"title":"제주 동부 화산·해안·민속마을 소그룹 일일 투어","description":"제주돌문화공원(돌 문화)에서 섭지코지(동부 해안 케이프), 성산일출봉(유네스코), 미천굴(용암동굴), 성읍민속마을(조선시대 민속마을)까지 이어지는 제주 동부 첫 방문 최적 코스입니다. 소그룹 미니버스, 공인 가이드, 4.8/5 평점.","badges":["첫 방문 추천","제주 동부 시그니처"],"duration":"8 hours"},"ja":{"title":"東済州火山・海岸・民俗村少人数日帰りツアー","description":"石の文化と火山の背景から始まり、海岸と城山日出峰を経て、日出ランドと城邑民俗村で締めくくる、東済州の一日を丁寧に設計したルートです。初めて済州を訪れる方に最適な6スポット構成。","badges":["初訪問者向け","東済州シグネチャー"],"duration":"8時間"},"zh":{"title":"东济州火山、海岸＆民俗村小团体一日游","description":"A clearly structured East Jeju day route that starts with stone culture and volcanic context, moves through the coast and Seongsan Ilchulbong, and finishes with Ilchulland and Seongeup Folk Village for a more complete day.","badges":["初访友善","济州东部招牌"],"duration":"8 hours"},"zh-TW":{"title":"東濟州火山、海岸＆民俗村小團體一日遊","description":"A clearly structured East Jeju day route that starts with stone culture and volcanic context, moves through the coast and Seongsan Ilchulbong, and finishes with Ilchulland and Seongeup Folk Village for a more complete day.","badges":["初訪友善","濟州東部招牌"],"duration":"8 hours"},"es":{"title":"Tour Jeju Este: Volcán, Costa Fotogénica y Aldea Folclórica","description":"Tour en grupo pequeño por el este de Jeju siguiendo la ruta más equilibrada de la isla: Parque de Cultura de Piedra de Jeju (mitología de la creación) → Cabo Seopjikoji (2,1 km de costa volcánica y escenario de K-dramas) → Seongsan Ilchulbong (Patrimonio Natural UNESCO) → Cueva Micheon en Ilchul Land → Aldea Folclórica Seongeup (ciudad joseonesa viva desde 1423). Recogida en hotel, todas las entradas incluidas.","badges":["Ideal para primera visita","Ruta estrella Jeju Este","Grupo pequeño"],"duration":"Un día (recogida en hotel)"}}'::jsonb, updated_at = NOW() WHERE slug = 'east-signature-nature-core';
UPDATE tours SET translations = '{"ko":{"title":"부산 출발 경주 고도 일일 투어","description":"유네스코 레거시 투어와 동일한 코스를 여유 있는 페이스로 진행합니다. 아홉산숲, 불국사, 국립경주박물관, 교촌한옥마을, 월정교까지 — 빠른 일정이 아닌 충분한 체류 시간을 원하는 분께 적합합니다.","badges":["소그룹","여유로운 페이스","부산 출발","조기 귀환"],"duration":"10.5 hours"},"ja":{"title":"慶州古都日帰りツアー（釜山発）— 穏やかなペース","description":"釜山発・新羅王朝の古都・慶州（BC57〜935年）への少人数日帰りツアー。UNESCOレガシーコースと同じ6スポットルート（アホプサン竹林→仏国寺→慶州国立博物館→校村韓屋村→月精橋）をより穏やかなペースで。10.5時間、釜山地下鉄3駅発着。","badges":["少人数","慶州","UNESCO","仏国寺","釜山発"],"duration":"10.5時間"},"zh":{"title":"釜山出发：庆州千年古都一日游","description":"Small-group day tour from Busan to Gyeongju, the Silla kingdom''s ancient capital (57 BCE–935 CE). Same classic six-attraction route as the UNESCO Legacy version (Ahopsan Bamboo Forest → Bulguksa Temple UNESCO → Gyeongju ssambap lunch → National Museum → Gyochon Hanok Village → Woljeonggyo Bridge) but at a calmer pace and earlier return (≈18:50). English/Chinese-speaking certified guide; mini-van; free admissions throughout (only Ahopsan ₩5,000 and lunch paid on-day).","badges":["小团体","舒适节奏","釜山出发","提早返程"],"duration":"10.5 hours"},"zh-TW":{"title":"釜山出發：慶州千年古都一日遊","description":"Small-group day tour from Busan to Gyeongju, the Silla kingdom''s ancient capital (57 BCE–935 CE). Same classic six-attraction route as the UNESCO Legacy version (Ahopsan Bamboo Forest → Bulguksa Temple UNESCO → Gyeongju ssambap lunch → National Museum → Gyochon Hanok Village → Woljeonggyo Bridge) but at a calmer pace and earlier return (≈18:50). English/Chinese-speaking certified guide; mini-van; free admissions throughout (only Ahopsan ₩5,000 and lunch paid on-day).","badges":["小團體","舒適節奏","釜山出發","提早返程"],"duration":"10.5 hours"},"es":{"title":"Tour Busan→Gyeongju: Capital de la Silla a Ritmo Pausado","description":"Las mismas seis paradas de Gyeongju que el tour UNESCO Legacy (Ahopsan, Bulguksa, Museo Nacional, Gyochon, Woljeonggyo) a un ritmo más tranquilo y con regreso ~30-40 minutos antes. Ideal para quienes prefieren detenerse más en cada parada sin correr. Mismo precio, grupo pequeño (~10 pasajeros). Los que quieren la misma ruta con más tiempo en el museo eligen el tour UNESCO Legacy (C2).","badges":["Grupo pequeño","Ritmo tranquilo","Desde Busan","Regreso temprano"],"duration":"Un día (ritmo pausado, regreso temprano)"}}'::jsonb, updated_at = NOW() WHERE slug = 'from-busan-gyeongju-ancient-capital-day-tour';
UPDATE tours SET translations = '{"ko":{"title":"인천 크루즈 기항지 서울 소그룹 투어","description":"인천 크루즈 터미널에서 출발해 경복궁(조선 왕궁), 북촌한옥마을(600년 한옥 거주지), 광장시장(점심), 인사동(전통 문화 거리)을 소그룹으로 하루에. 귀선 시각 보장.","badges":["크루즈 기항 일일 투어","소형 합승 밴","인천항 픽업","9시간 서비스 창"],"duration":"9 hours"},"ja":{"title":"仁川クルーズ寄港地ソウル日帰りツアー","description":"仁川クルーズターミナル発着のシェアバン日帰りツアー。9時間でソウル中心部の主要スポットを巡る：景福宮（火曜は昌徳宮）→北村韓屋村→広蔵市場の昼食（ソウル最古の常設市場）→仁寺洞文化通り。英語ガイド付き少人数制。","badges":["クルーズ寄港地","ソウル","仁川発","景福宮","韓屋村"],"duration":"船→船"},"zh":{"title":"仁川邮轮码头出发首尔中心一日游","description":"Shared-van day tour from Incheon Cruise Terminal hitting Seoul''s headline central-city stops in a single 9-hour window: Gyeongbokgung Palace (or Changdeokgung on Tuesdays), Bukchon Hanok Village, lunch at Gwangjang Market (the city''s most-photographed streetfood alley), and Insadong cultural street. Pickup calibrated to your specific ship''s disembarkation; certified English/Chinese-speaking guide; ≈75 min return drive built in.","badges":["邮轮停靠一日游","共乘小型厢型车","仁川港接送","9小时行程"],"duration":"9 hours"},"zh-TW":{"title":"仁川郵輪碼頭出發首爾中心一日遊","description":"Shared-van day tour from Incheon Cruise Terminal hitting Seoul''s headline central-city stops in a single 9-hour window: Gyeongbokgung Palace (or Changdeokgung on Tuesdays), Bukchon Hanok Village, lunch at Gwangjang Market (the city''s most-photographed streetfood alley), and Insadong cultural street. Pickup calibrated to your specific ship''s disembarkation; certified English/Chinese-speaking guide; ≈75 min return drive built in.","badges":["郵輪停靠一日遊","共乘小型廂型車","仁川港接送","9小時行程"],"duration":"9 hours"},"es":{"title":"From Incheon: Seoul Day Tour for Cruise Guests (Small Group)","description":"Tour en furgoneta compartida desde el terminal de cruceros de Incheon hasta el corazón histórico de Seúl (9 horas): Palacio Gyeongbokgung (Ceremonia de Cambio de Guardia) → Bukchon Hanok Village → almuerzo en el Mercado Gwangjang (el más antiguo de Seúl) → Calle Insadong. Regreso garantizado 90-120 min antes de la salida.","badges":["Cruise excursion","Small shared van","Pickup at Incheon port","9-hour window"],"duration":"9 hours"}}'::jsonb, updated_at = NOW() WHERE slug = 'from-incheon-seoul-day-tour-cruise-guests';
UPDATE tours SET translations = '{"ko":{"title":"인천 크루즈 기항지 서울 프라이빗 투어","description":"인천 크루즈 터미널에서 갱웨이 픽업, 경복궁+수문장 교대, 북촌한옥마을+인사동, 선택 점심, N서울타워(남산), 명동 또는 조계사 중 선택. 완전 프라이빗, 귀선 보장.","badges":["프라이빗","크루즈 기항지 관광","기항지 관광","서울 핵심 코스","맞춤 가능","귀선 보장"],"duration":"8 hours"},"ja":{"title":"仁川→ソウルプライベートクルーズ寄港地観光","description":"出航時間を基準に逆算設計された仁川クルーズターミナル発着のプライベートカーチャーター。乗船口でのピックアップから景福宮・北村韓屋村・仁寺洞・Nソウルタワー・明洞（または曹渓寺）まで、英語ガイド付き専用車でソウルを自分のペースで。","badges":["クルーズ寄港地","ソウル","プライベート","Nソウルタワー","仁川発"],"duration":"船→船"},"zh":{"title":"仁川至首尔私人包车邮轮岸上一日游","description":"An 8-hour private car charter built around your ship''s all-aboard time, not a fixed schedule. Gangway pickup at Incheon Cruise Terminal, English-speaking driver-guide, and a customizable route through Gyeongbokgung Palace, Bukchon Hanok Village + Insadong, lunch of your choice, N Seoul Tower, and Myeongdong or Jogyesa Temple. The driver-guide holds a 60-minute traffic buffer before sailaway so you never miss the ship.","badges":["私人专属","邮轮岸上观光","邮轮岸上行程","首尔精华","可自订行程","准时返船保证"],"duration":"8 hours"},"zh-TW":{"title":"仁川至首爾私人包車郵輪岸上一日遊","description":"An 8-hour private car charter built around your ship''s all-aboard time, not a fixed schedule. Gangway pickup at Incheon Cruise Terminal, English-speaking driver-guide, and a customizable route through Gyeongbokgung Palace, Bukchon Hanok Village + Insadong, lunch of your choice, N Seoul Tower, and Myeongdong or Jogyesa Temple. The driver-guide holds a 60-minute traffic buffer before sailaway so you never miss the ship.","badges":["私人專屬","郵輪岸上觀光","郵輪岸上行程","首爾精華","可自訂行程","準時返船保證"],"duration":"8 hours"},"es":{"title":"Incheon to Seoul Private Car Shore Excursion for Cruise Guests","description":"Excursión privada en coche desde el terminal de cruceros de Incheon a Seúl: Palacio Gyeongbokgung (Cambio de Guardia) → Bukchon + Insadong → almuerzo libre → Torre N de Seúl (observatorio 479 m) → Myeongdong o Templo Jogyesa (a elegir). Más paradas que la furgoneta compartida. Regreso garantizado según la hora de salida.","badges":["Private","Cruise","Shore excursion","Seoul highlights","Customizable","Guaranteed return"],"duration":"8 hours"}}'::jsonb, updated_at = NOW() WHERE slug = 'incheon-seoul-private-car-shore-excursion-cruise';
UPDATE tours SET translations = '{"ko":{"title":"제주 동부 봄 벚꽃·유채 시즌 투어","description":"전농로(제주 최고 벚꽃 거리), 녹산로(가시리 10km 벚꽃+유채 도로), 미천굴 용암동굴(일출랜드), 성산일출봉(유네스코) 포토 스톱을 소그룹으로 봄 하루에 일주합니다.","badges":["봄 한정","벚꽃 시즌","제주 동부"],"duration":"8 hours"},"ja":{"title":"済州桜ツアー・東ルート・春限定","description":"済州の春を象徴する東ルート桜ツアー：全農路（済州市内最古の桜並木）→緑山路（加時里10kmの桜＋菜の花の絶景ロード）→密川洞窟→日出ランドのテーマ庭園→城山日出峰（UNESCO）。春のベストフォトスポットを一日で。","badges":["春限定","済州","桜","菜の花","UNESCO"],"duration":"春限定（運営期間は開花状況による）"},"zh":{"title":"济州东部赏樱小团体一日游","description":"Spring-only east Jeju route through cherry blossom streets, the 10km canola road, a lava tube cave, and the iconic Seongsan crater.","badges":["仅限春季","樱花季","济州东部"],"duration":"8 hours"},"zh-TW":{"title":"濟州東部賞櫻小團體一日遊","description":"Spring-only east Jeju route through cherry blossom streets, the 10km canola road, a lava tube cave, and the iconic Seongsan crater.","badges":["僅限春季","櫻花季","濟州東部"],"duration":"8 hours"},"es":{"title":"Tour Cerezos Jeju Este: Jeonnong-ro, Noksan-ro, Cueva de Lava y Seongsan","description":"Los cerezos del este de Jeju en tres formatos distintos: la calle Jeonnong-ro (el bulevar de cerezos más antiguo de Jeju, 1,2 km de túnel floral) → la carretera Noksan-ro de Gasi-ri (10 km de cerezos + colza amarilla, la imagen de primavera más reproducida de Jeju) → almuerzo → Cueva Micheon en Ilchul Land → jardines de primavera → Seongsan Ilchulbong (triple UNESCO) como foto final.","badges":["Solo primavera","Cerezos + canola","Jeju Este","Seongsan UNESCO"],"duration":"Un día (solo mar-abr)"}}'::jsonb, updated_at = NOW() WHERE slug = 'jeju-cherry-blossom-tour-east-route';
UPDATE tours SET translations = '{"ko":{"title":"제주 크루즈 기항지 관광 — 버스 투어 (대형 버스)","description":"크루즈 기항지 대형 버스 투어로, 기항 항구에 따라 동부 코스(제주항 — 성산일출봉·섭지코지·성읍민속마을) 또는 남부 코스(강정항 — 한라산+올레)로 진행됩니다. 귀선 시각 보장, 전 입장료 포함, 공인 가이드.","badges":["크루즈 기항 일일 투어","귀선 시각 배려 코스","알뜰 크루즈 플랜","대형 버스"],"duration":"8 hours"},"ja":{"title":"済州クルーズ寄港地観光バスツアー（大型コーチ）","description":"寄港地対応の済州日帰りツアー：済州港（北）と江汀港（南）の2ルートバリアント。済州港発は東部UNESCOルート（城山日出峰・摂地可支・城邑民俗村）、江汀港発は漢拏山高地＋オルレ市場ルート。クルーズ日程に合わせた8時間設計。","badges":["クルーズ寄港地","済州","大型コーチ","UNESCO","ターミナル発着"],"duration":"8時間"},"zh":{"title":"济州邮轮岸上观光——大型游览车行程","description":"A bus tour (large coach) cruise shore excursion that adapts the route to your cruise port. Jeju Port (north) runs an east-coast UNESCO route via Seongsan Ilchulbong; Gangjeong Port (south) runs a Hallasan 1100 + south-coast geology + Olle Market route. Both return to the cruise terminal with comfortable buffer.","badges":["邮轮停靠一日游","配合邮轮时刻","经济邮轮方案","大型游览车"],"duration":"8 hours"},"zh-TW":{"title":"濟州郵輪岸上觀光——大型遊覽車行程","description":"A bus tour (large coach) cruise shore excursion that adapts the route to your cruise port. Jeju Port (north) runs an east-coast UNESCO route via Seongsan Ilchulbong; Gangjeong Port (south) runs a Hallasan 1100 + south-coast geology + Olle Market route. Both return to the cruise terminal with comfortable buffer.","badges":["郵輪停靠一日遊","配合郵輪時刻","經濟郵輪方案","大型遊覽車"],"duration":"8 hours"},"es":{"title":"Jeju Cruise Shore Excursion — Bus Tour (Large Coach)","description":"Tour en autocar de gran capacidad desde el terminal de cruceros de Jeju, con dos variantes según el puerto de atraque: Puerto de Jeju (norte) → Seongsan Ilchulbong (triple Patrimonio UNESCO) → Cabo Seopjikoji → almuerzo → Aldea Seongeup; Puerto Gangjeong (sur) → ruta alternativa por el Hallasan. Regreso garantizado 90-120 min antes de la salida.","badges":["Cruise excursion","Port-aware routing","Budget cruise","Large coach"],"duration":"8 hours"}}'::jsonb, updated_at = NOW() WHERE slug = 'jeju-cruise-shore-excursion-bus-tour';
UPDATE tours SET translations = '{"ko":{"title":"제주 크루즈 기항지 관광 — 소그룹 투어","description":"크루즈 기항지 소그룹 투어. 기항 항구에 따라 동부 코스(제주항 — 성산일출봉·섭지코지·성읍민속마을) 또는 남부 코스(강정항)로 진행. 귀선 시각 보장, 공인 가이드.","badges":["크루즈 기항 일일 투어","귀선 시각 배려 코스","프리미엄 크루즈 플랜","소그룹"],"duration":"8 hours"},"ja":{"title":"済州クルーズ寄港地少人数観光ツアー","description":"寄港地に合わせて2ルート対応の済州クルーズ寄港地少人数観光ツアー。済州港（北）発は東海岸UNESCOルート（城山日出峰→摂地可支→城邑民俗村）；江汀港（南）発は漢拏山1100高地ルート。帰船時間の90〜120分前にターミナル帰着保証。","badges":["クルーズ寄港地","済州","少人数","UNESCO","ターミナル発着"],"duration":"船→船"},"zh":{"title":"济州邮轮岸上观光——小团体厢型车行程","description":"A small group tour cruise shore excursion that adapts the route to your cruise port. Jeju Port (north) runs an east-coast UNESCO route via Seongsan Ilchulbong; Gangjeong Port (south) runs a Hallasan 1100 + south-coast geology + Olle Market route. Both return to the cruise terminal with comfortable buffer.","badges":["邮轮停靠一日游","配合邮轮时刻","高级邮轮方案","小团体"],"duration":"8 hours"},"zh-TW":{"title":"濟州郵輪岸上觀光——小團體廂型車行程","description":"A small group tour cruise shore excursion that adapts the route to your cruise port. Jeju Port (north) runs an east-coast UNESCO route via Seongsan Ilchulbong; Gangjeong Port (south) runs a Hallasan 1100 + south-coast geology + Olle Market route. Both return to the cruise terminal with comfortable buffer.","badges":["郵輪停靠一日遊","配合郵輪時刻","高級郵輪方案","小團體"],"duration":"8 hours"},"es":{"title":"Jeju Cruise Shore Excursion — Small Group Tour","description":"Excursión en escala de crucero por Jeju en grupo pequeño con dos rutas según el puerto: Puerto de Jeju (norte) → Seongsan Ilchulbong (triple UNESCO) → Cabo Seopjikoji → almuerzo → Aldea Seongeup; Puerto Gangjeong (sur) → ruta alternativa por el Hallasan. Grupo más reducido que el autocar grande. Regreso garantizado.","badges":["Cruise excursion","Port-aware routing","Premium cruise","Small group"],"duration":"8 hours"}}'::jsonb, updated_at = NOW() WHERE slug = 'jeju-cruise-shore-excursion-small-group-tour';
UPDATE tours SET translations = '{"ko":{"title":"제주 동부 유네스코 명소 일일 투어","description":"제주 동부 유네스코 및 핵심 명소를 9시간 소그룹으로 일주하는 투어입니다. 함덕 서우봉해변, 성읍민속마을(유네스코), 미천굴 용암동굴(만장굴 운영 중단 기간 대체), 성산일출봉(유네스코 세계자연유산), 해녀박물관(유네스코 해녀문화) 포함. 전 입장료 포함, 공인 가이드, 1,148건 기준 4.9/5 평점.","badges":["소그룹","제주","제주 동부","유네스코","합리적 가격","전 입장료 포함"],"duration":"9 hours"},"ja":{"title":"済州東部ユネスコ世界遺産日帰りツアー","description":"東済州のユネスコ遺産スポットを9時間で巡る少人数日帰りツアー。咸徳서우봉ビーチ、城邑民俗村（ユネスコ）、密川洞窟溶岩トンネル（万丈窟閉鎖中の代替スポット）、城山日出峰（ユネスコ自然遺産）、海女博物館を一日で網羅。全入場料込み、英語・中国語対応の認定ガイド付き。1,148件のクチコミで4.9/5の高評価。","badges":["スモールグループ","済州島","東済州","ユネスコ","お得","全入場料込み"],"duration":"9時間"},"zh":{"title":"济州东部UNESCO景点一日游","description":"A small-group day tour covering eastern Jeju''s UNESCO and signature stops in a single 9-hour loop — Hamdeok Seoubong Beach, Seongeup Folk Village, the Micheon Cave lava tube system (current alternate to closed Manjanggul), Seongsan Ilchulbong (UNESCO Sunrise Peak), and the Haenyeo Museum dedicated to Jeju''s UNESCO-listed women divers. ALL admissions included; certified English/Chinese-speaking guide; rated 4.9/5 across 1,148 reviews.","badges":["小团体","济州","济州东部","世界遗产","超值定价","所有门票已包含"],"duration":"9 hours"},"zh-TW":{"title":"濟州東部UNESCO景點一日遊","description":"A small-group day tour covering eastern Jeju''s UNESCO and signature stops in a single 9-hour loop — Hamdeok Seoubong Beach, Seongeup Folk Village, the Micheon Cave lava tube system (current alternate to closed Manjanggul), Seongsan Ilchulbong (UNESCO Sunrise Peak), and the Haenyeo Museum dedicated to Jeju''s UNESCO-listed women divers. ALL admissions included; certified English/Chinese-speaking guide; rated 4.9/5 across 1,148 reviews.","badges":["小團體","濟州","濟州東部","世界遺產","超值定價","所有門票已包含"],"duration":"9 hours"},"es":{"title":"Tour Jeju Este: Patrimonio UNESCO, Cueva de Lava y Haenyeo","description":"Excursión de un día en grupo pequeño por el este de Jeju cubriendo los hitos UNESCO y los puntos icónicos en un único recorrido de 9 horas: Playa Hamdeok Seoubong, Aldea Folclórica Seongeup, Cueva Micheon en Ilchul Land, Seongsan Ilchulbong (Pico del Amanecer, Patrimonio Natural UNESCO) y el Museo Haenyeo. Todas las entradas incluidas, guía certificado.","badges":["Grupo pequeño","Jeju Este","UNESCO","Haenyeo","Entradas incluidas"],"duration":"9 horas"}}'::jsonb, updated_at = NOW() WHERE slug = 'jeju-eastern-unesco-spots-day-tour';
UPDATE tours SET translations = '{"ko":{"title":"제주 그랜드 하이라이트 루프 소그룹 일일 투어","description":"하루 시간이 제한된 여행자를 위한 고밀도 제주 일주 투어입니다. 어승생악 오름(한라산), 대포주상절리(유네스코), 정방폭포(아시아 유일 해안 직폭), 성산일출봉(유네스코 세계자연유산) 포함. 소그룹 미니버스, 공인 가이드.","badges":["당일 여행 최고 선택","빠른 하이라이트"],"duration":"9–9.5 hours"},"ja":{"title":"済州グランドハイライトループ少人数日帰りツアー","description":"時間が限られた旅行者のための高効率・済州全島ルート。漢拏山、南海岸、城山日出峰を一日でリンクします。","badges":["1日訪問者向け","ハイライト集中型"],"duration":"9〜9.5時間"},"zh":{"title":"济州全岛精华小团体一日游","description":"济州最受欢迎的全岛精华路线——联合国世界遗产火山口、熔岩洞穴、玄武岩海崖、山茶花丘，小团体出行。","badges":["一日游首选","快节奏精华"],"duration":"9–9.5 hours"},"zh-TW":{"title":"濟州全島精華小團體一日遊","description":"濟州最受歡迎的全島精華路線——聯合國世界遺產火山口、熔岩洞穴、玄武岩海崖、山茶花丘，小團體出行。","badges":["一日遊首選","快節奏精華"],"duration":"9–9.5 hours"},"es":{"title":"Tour Jeju Completo en un Día: Hallasan, Acantilados y Seongsan","description":"El circuito de alta densidad de Jeju para viajeros con un único día en la isla: senderismo en el Hallasan (Eoseungsaengak, 1.169 m), Acantilado Jusangjeolli de basalto hexagonal (Monumento Natural + Geoparque UNESCO), almuerzo en Seogwipo, Cascada Jeongbang (la única de Asia que cae directamente al mar) y Seongsan Ilchulbong (triple Patrimonio UNESCO) como gran final. Grupo pequeño.","badges":["Ideal para un día en Jeju","Highlights rápidos","Toda la isla","UNESCO"],"duration":"Un día (alta densidad)"}}'::jsonb, updated_at = NOW() WHERE slug = 'jeju-grand-highlights-loop';
UPDATE tours SET translations = '{"ko":{"title":"제주 동부 수국 축제 소그룹 투어","description":"제주 동부 수국 시즌 한정(5월 말~7월 중순) 소그룹 투어. 함덕해변, 성읍민속마을(유네스코), 성산일출봉(유네스코), 일출랜드 수국 축제+미천굴, 휴애리 자연생활공원 수국 포함.","badges":["소그룹","제주","수국","시즌 한정","여름 한정","유네스코","축제"],"duration":"9 hours"},"ja":{"title":"済州アジサイ祭り東ルートツアー（夏限定）","description":"済州東部アジサイ祭りシーズン（6〜8月）の少人数日帰りツアー。咸徳서우봉海岸→城邑民俗村→城山日出峰（UNESCO）→日出ランド（アジサイ祭り＋密川洞窟）→ヒュアリ自然公園（韓国有数のアジサイスポット）。9時間、済州市内ホテル発着。","badges":["夏限定","済州","アジサイ祭り","UNESCO","東ルート"],"duration":"9時間（夏限定）"},"zh":{"title":"济州绣球花节一日游：东部路线","description":"A seasonal small-group day-tour of east Jeju built around the island''s hydrangea festivals (late May to mid-July, peak mid-June) at Hueree Natural Park and Ilchul Land. The route also covers two UNESCO World Heritage sites — Seongsan Ilchulbong (Sunrise Peak) and Seongeup Folk Village — plus Hamdeok Beach and the Micheon Cave lava tube. Hotel pickup in Jeju City, English/Chinese-speaking licensed guide-driver.","badges":["小团体","济州","绣球花","季节限定","夏季限定","世界遗产","节庆活动"],"duration":"9 hours"},"zh-TW":{"title":"濟州繡球花節一日遊：東部路線","description":"A seasonal small-group day-tour of east Jeju built around the island''s hydrangea festivals (late May to mid-July, peak mid-June) at Hueree Natural Park and Ilchul Land. The route also covers two UNESCO World Heritage sites — Seongsan Ilchulbong (Sunrise Peak) and Seongeup Folk Village — plus Hamdeok Beach and the Micheon Cave lava tube. Hotel pickup in Jeju City, English/Chinese-speaking licensed guide-driver.","badges":["小團體","濟州","繡球花","季節限定","夏季限定","世界遺產","節慶活動"],"duration":"9 hours"},"es":{"title":"Tour Festival de Hortensias Jeju Este: Seongsan, Ilchul Land y Parque Hueree","description":"El azul del verano de Jeju en un día: Playa Hamdeok (aguas esmeralda) → Aldea Folclórica Seongeup (1423) → Seongsan Ilchulbong (triple UNESCO) → Ilchul Land (Festival de Hortensias + Cueva Micheon) → Parque Natural Hueree (el mayor espectáculo de hortensias del sur de Jeju). Solo temporada de hortensias (junio-agosto). Grupo pequeño, recogida en hotel.","badges":["Solo verano","Festival hortensias","Jeju Este","Seongsan UNESCO","Grupo pequeño"],"duration":"9 horas (solo jun-ago)"}}'::jsonb, updated_at = NOW() WHERE slug = 'jeju-hydrangea-festival-tour-east-route';
UPDATE tours SET translations = '{"ko":{"title":"제주 서남부 수국 축제 소그룹 투어","description":"협재해변, 한림공원 수국 축제(개방형 수국 정원), 주상절리(유네스코)·천제연폭포(묶음 관람), 카멜리아힐 수국 터널, 오설록 티뮤지엄을 소그룹으로 여름 하루에.","badges":["여름 한정","수국 시즌","Southwest Jeju"],"duration":"9 hours"},"ja":{"title":"済州アジサイ祭り南西ルートツアー（夏限定）","description":"済州南西部の夏限定日帰りルート — エメラルドの協才海岸→翰林公園のアジサイ祭り（溶岩洞窟も）→大浦柱状節理（UNESCO認定）→天帝淵の三段の滝→カメリアヒルのアジサイトンネル→雪緑茶博物館の茶畑。","badges":["夏限定","済州","アジサイ祭り","翰林公園","南西ルート"],"duration":"夏限定（一日ツアー）"},"zh":{"title":"济州西南绣球花节小团体一日游","description":"Summer-only southwest Jeju route — emerald beach, hydrangea festival gardens, UNESCO columnar cliff, three-tier waterfall, hydrangea tunnel, and tea fields.","badges":["仅限夏季","绣球花季","济州西南部"],"duration":"9 hours"},"zh-TW":{"title":"濟州西南繡球花節小團體一日遊","description":"Summer-only southwest Jeju route — emerald beach, hydrangea festival gardens, UNESCO columnar cliff, three-tier waterfall, hydrangea tunnel, and tea fields.","badges":["僅限夏季","繡球花季","濟州西南部"],"duration":"9 hours"},"es":{"title":"Tour Festival de Hortensias Jeju Suroeste: Playa, Cueva, Cascada y Campos de Té","description":"El festival de hortensias del suroeste de Jeju: Playa Hyeopjae (arena blanca, aguas turquesa) → Hallim Park (festival de hortensias + cuevas de lava volcánica) → almuerzo → Acantilado Jusangjeolli (Geoparque UNESCO) + Cascadas Cheonjeyeon (Monumento Natural) → Camellia Hill (el famoso túnel de hortensias) → Osulloc (campos de té verde). Solo junio-agosto.","badges":["Solo verano","Festival hortensias","Jeju Suroeste","Túnel de hortensias Camellia Hill"],"duration":"Un día (solo jun-ago)"}}'::jsonb, updated_at = NOW() WHERE slug = 'jeju-hydrangea-festival-tour-southwest-route';
UPDATE tours SET translations = '{"ko":{"title":"제주 섬 프라이빗 전세 차량 투어","description":"유자격 드라이버 가이드와 에어컨 프라이빗 차량으로 제주를 9시간 동안 완전히 맞춤 이동하는 투어입니다. 동부(유네스코·한드 해안), 서부(해변·차밭·카페 해안), 남부(폭포·화산 해안) 추천 루트 또는 완전 커스텀 코스 선택 가능.","badges":["프라이빗 전세 투어","코스 맞춤 가능","호텔 픽업 포함"],"duration":"9 hours"},"ja":{"title":"済州島プライベートカーチャーターツアー","description":"認定ドライバーガイドとエアコン付き専用車でご自分だけの済州一日ツアーをデザイン。東ルート（UNESCO・Kドラマ海岸）、西ルート（ビーチ・茶畑・カフェ通り）、南ルート（滝・火山海岸）、または完全カスタムルートから選択できます。9時間チャーター、済州市内のホテルからの送迎込み。","badges":["プライベート","済州","カスタムルート","ドライバーガイド","専用車"],"duration":"9時間"},"zh":{"title":"济州岛私人包车一日游","description":"A 9-hour private car charter for Jeju with a licensed driver-guide. Three recommended routes (East, West, South) cover the island''s most-loved sights, or build your own from UNESCO landmarks, K-drama spots, beaches, tea fields, and traditional markets. Hotel pickup is included anywhere on the island.","badges":["私人包车游","路线可自订","饭店接送含括"],"duration":"9 hours"},"zh-TW":{"title":"濟州島私人包車一日遊","description":"A 9-hour private car charter for Jeju with a licensed driver-guide. Three recommended routes (East, West, South) cover the island''s most-loved sights, or build your own from UNESCO landmarks, K-drama spots, beaches, tea fields, and traditional markets. Hotel pickup is included anywhere on the island.","badges":["私人包車遊","路線可自訂","飯店接送含括"],"duration":"9 hours"},"es":{"title":"Tour Privado Jeju con Chófer-Guía: Ruta Este, Oeste, Sur o Personalizada","description":"Diseñe su propio día en Jeju con un chófer-guía certificado en un coche privado con aire acondicionado. Elija entre tres rutas recomendadas — Ruta Este (UNESCO y costa K-drama), Ruta Oeste (playas, té y cafés costeros) o Ruta Sur (cascadas y costa volcánica) — o componga su propio itinerario a medida. Recogida en hotel, 9 horas, entradas incluidas.","badges":["Tour privado","Ruta personalizable","Recogida en hotel incluida"],"duration":"9 horas (servicio privado)"}}'::jsonb, updated_at = NOW() WHERE slug = 'jeju-island-private-car-charter-tour';
UPDATE tours SET translations = '{"ko":{"title":"제주 남부 유네스코 핵심 명소 일일 투어","description":"제주 남부 핵심 유네스코 명소와 자연 경관을 소그룹으로 일주하는 투어입니다. 어승생악 트레일(한라산 기생화산), 카멜리아힐 꽃 정원, 천제연폭포(3단 폭포), 대포주상절리(유네스코), 오설록 티뮤지엄 포함. 전 입장료 포함, 공인 가이드, 648건 기준 4.9/5 평점.","badges":["소그룹","제주","제주 남부","유네스코","합리적 가격","쇼핑 없음"],"duration":"9 hours"},"ja":{"title":"済州南部ユネスコ世界遺産日帰りツアー","description":"済州南部の主要ユネスコスポットを9時間で巡る少人数日帰りツアー。어승생악トレイル（漢拏山（ハルラサン）自然遺産）、山茶花の丘（カメリアヒル）、天帝淵の滝、大浦柱状節理、雪緑茶博物館（O''Sulloc）を一日で網羅。全入場料込み、英語・中国語対応の認定ガイド付き。648件のクチコミで4.9/5。","badges":["スモールグループ","済州島","南済州","ユネスコ","お得","全入場料込み"],"duration":"9時間"},"zh":{"title":"济州南部精选UNESCO景点一日游","description":"A small-group day tour through southern Jeju''s signature stops — the Eoseungsaengak Trail along Hallasan (UNESCO biosphere), Camellia Hill garden, the three-tier Cheonjeyeon Waterfall, the hexagonal Jusangjeolli Cliff, and the O''sulloc Tea Museum. Four pickup points across Jeju City and the airport, certified English/Chinese-speaking guide, all admissions included, no shopping pressure. The most reviewed entry-level Jeju tour at 4.9/5 across 648 reviews.","badges":["小团体","济州","济州南部","世界遗产","超值定价","无购物行程"],"duration":"9 hours"},"zh-TW":{"title":"濟州南部精選UNESCO景點一日遊","description":"A small-group day tour through southern Jeju''s signature stops — the Eoseungsaengak Trail along Hallasan (UNESCO biosphere), Camellia Hill garden, the three-tier Cheonjeyeon Waterfall, the hexagonal Jusangjeolli Cliff, and the O''sulloc Tea Museum. Four pickup points across Jeju City and the airport, certified English/Chinese-speaking guide, all admissions included, no shopping pressure. The most reviewed entry-level Jeju tour at 4.9/5 across 648 reviews.","badges":["小團體","濟州","濟州南部","世界遺產","超值定價","無購物行程"],"duration":"9 hours"},"es":{"title":"Tour Jeju Sur: UNESCO, Cascadas, Acantilados y Campos de Té","description":"Circuito de un día en grupo pequeño por el sur de Jeju: senderismo en el Hallasan (Patrimonio UNESCO), jardín botánico Camellia Hill (flores todo el año), Cascadas Cheonjeyeon (Monumento Natural), Acantilado Jusangjeolli de basalto hexagonal (Monumento Natural + Geoparque UNESCO), campos de té y Museo Osulloc. Entradas incluidas, sin paradas de compras.","badges":["Grupo pequeño","Jeju Sur","UNESCO","Sin compras","Entradas incluidas"],"duration":"9 horas"}}'::jsonb, updated_at = NOW() WHERE slug = 'jeju-southern-top-unesco-spots-tour';
UPDATE tours SET translations = '{"ko":{"title":"제주 서부·남부 정통 일일 투어","description":"한라산 1100고지 습지(람사르·유네스코)부터 주상절리(유네스코 지질공원), 송악산 전망 둘레길, 천제연폭포, 오설록 티뮤지엄, 협재해변 카페거리까지 이어지는 제주 서부·남부 정통 루프입니다. 쇼핑 경유지 없음, 소그룹, 공인 가이드.","badges":["소그룹","제주","West & South Jeju","유네스코","카페 문화","해안 풍경"],"duration":"9 hours"},"ja":{"title":"済州西南部オーセンティック終日ツアー","description":"済州の西海岸と南海岸を一日でめぐる少人数ツアー — 漢拏山1100高地湿地（UNESCO）、六角形の大浦柱状節理、松岳山のパノラマ展望台、天帝淵の滝、雪緑茶博物館、協才海岸カフェ通り。姉妹ツアー（南部UNESCOツアー）と同じオペレーターながら、より「ライフスタイル重視」のルート設計 — 火山地形と劇的な海岸線、海辺のおしゃれなカフェが融合する済州を体感できます。","badges":["少人数","済州","済州西部・南部","UNESCO","カフェ文化","海岸"],"duration":"9時間"},"zh":{"title":"济州西部＆南部全日深度在地行程","description":"A small-group day tour pairing Jeju''s western and southern coasts in a single loop — Hallasan''s 1100 Altitude Wetland (UNESCO), the hexagonal Jusangjeolli Cliff, Songaksan''s panoramic viewpoint, Cheonjeyeon Waterfall, O''sulloc Tea Museum, and the Hyeopjae Beach café strip on the west coast. Same operator as the Southern UNESCO tour but with a more lifestyle-oriented framing — ''volcanic landscapes meet dramatic coastlines and trendy seaside cafés.''","badges":["小团体","济州","济州西南部","世界遗产","咖啡文化","海岸风情"],"duration":"9 hours"},"zh-TW":{"title":"濟州西部＆南部全日深度在地行程","description":"A small-group day tour pairing Jeju''s western and southern coasts in a single loop — Hallasan''s 1100 Altitude Wetland (UNESCO), the hexagonal Jusangjeolli Cliff, Songaksan''s panoramic viewpoint, Cheonjeyeon Waterfall, O''sulloc Tea Museum, and the Hyeopjae Beach café strip on the west coast. Same operator as the Southern UNESCO tour but with a more lifestyle-oriented framing — ''volcanic landscapes meet dramatic coastlines and trendy seaside cafés.''","badges":["小團體","濟州","濟州西南部","世界遺產","咖啡文化","海岸風情"],"duration":"9 hours"},"es":{"title":"Tour Jeju Oeste-Sur: Hallasan, Acantilados, Té y Cafés Costeros","description":"Tour de un día en grupo pequeño que combina el interior volcánico y la costa oeste de Jeju: Humedal Hallasan 1100 (Ramsar + Reserva Biosfera UNESCO) → Acantilado Jusangjeolli (Geoparque UNESCO) → Songaksan (vistas al Maru y al Mar del Sur) → Cascadas Cheonjeyeon → Osulloc → Playa Hyeopjae con los cafés costeros de Jeju. Un itinerario más tranquilo y auténtico que los circuitos del este.","badges":["Grupo pequeño","Jeju Oeste y Sur","UNESCO","Cultura cafetera","Costa"],"duration":"9 horas"}}'::jsonb, updated_at = NOW() WHERE slug = 'jeju-west-south-full-day-authentic-tour';
UPDATE tours SET translations = '{"ko":{"title":"제주 겨울 감귤·설경·동백 소그룹 투어","description":"한라산 어리목 트레일(겨울 설경), 감귤(귤) 따기 체험(겨울 할라봉 절정), 카멜리아힐(동백꽃 절정), 대포주상절리(유네스코), 천제연폭포를 포함한 제주 겨울 한정 소그룹 투어.","badges":["소그룹","제주","겨울 한정","시즌 한정","감귤 따기","동백꽃","설경"],"duration":"9 hours"},"ja":{"title":"済州冬ツアー：みかん・雪・山茶花（南西部）","description":"冬の済州（12〜2月）にしか体験できない3大テーマで組んだ南西部日帰りツアー：漢拏山御利目コースの樹氷林ハイク・カメリアヒルの満開の山茶花（冬がピーク）・ハルラボンのみかん狩り体験。さらに大浦柱状節理と天帝淵の滝も。","badges":["冬限定","済州","みかん狩り","山茶花","漢拏山"],"duration":"冬限定（一日ツアー）"},"zh":{"title":"济州冬季西南路线：橘子采摘、雪景＆山茶花一日游","description":"A seasonal winter day-tour of southwest Jeju (December through February) built around the three things only Jeju does well in winter: snow on Hallasan''s slopes, red camellias in full bloom at Camellia Hill, and pick-your-own Jeju tangerines (gyul) at a working orchard. The route also covers Cheonjeyeon Falls, Jusangjeolli columnar cliffs, and the Osulloc Tea Museum. Hotel pickup in Jeju City, English/Chinese-speaking licensed guide.","badges":["小团体","济州","冬季限定","季节限定","橘子采摘","山茶花","雪景"],"duration":"9 hours"},"zh-TW":{"title":"濟州冬季西南路線：橘子採摘、雪景＆山茶花一日遊","description":"A seasonal winter day-tour of southwest Jeju (December through February) built around the three things only Jeju does well in winter: snow on Hallasan''s slopes, red camellias in full bloom at Camellia Hill, and pick-your-own Jeju tangerines (gyul) at a working orchard. The route also covers Cheonjeyeon Falls, Jusangjeolli columnar cliffs, and the Osulloc Tea Museum. Hotel pickup in Jeju City, English/Chinese-speaking licensed guide.","badges":["小團體","濟州","冬季限定","季節限定","橘子採摘","山茶花","雪景"],"duration":"9 hours"},"es":{"title":"Tour Invierno Jeju Suroeste: Nieve en el Hallasan, Recogida de Mandarinas y Camelias","description":"Las tres experiencias únicas del invierno de Jeju en un día: senderismo en el sendero nevado Eorimok del Hallasan (árboles cubiertos de escarcha y nieve en la montaña más alta de Corea) → recogida de mandarinas Hallabong de invierno en una granja local → almuerzo → Camellia Hill (las camelias rojas en su pico de diciembre-enero) → Acantilado Jusangjeolli → Cascadas Cheonjeyeon. Diciembre-febrero, grupo pequeño, recogida en hotel.","badges":["Solo invierno","Nieve + mandarinas + camelias","Grupo pequeño","Recogida en hotel"],"duration":"Un día (dic-feb)"}}'::jsonb, updated_at = NOW() WHERE slug = 'jeju-winter-southwest-tangerine-snow-camellia-tour';
UPDATE tours SET translations = '{"ko":{"title":"포천 산정호수·허브아일랜드·아트밸리 소그룹 투어","description":"산정호수(명성산·철봉산 품은 고산 호수, 4km 산책로), 포천 허브아일랜드(약 8만2,000㎡ 지중해 테마 허브 정원), 포천 아트밸리(1970년대 화강암 채석장 → 예술 공원, 조각공원+천주호)를 소그룹으로.","badges":["자연·사진 투어","시즌 하이라이트","낭만 야경"],"duration":"10 hours"},"ja":{"title":"抱川日帰りツアー：山正湖・ハーブアイランド・アートバレー","description":"ソウルから約1時間の京畿道・抱川市への少人数日帰りツアー。「韓国のプロヴァンス」とも呼ばれる山に囲まれた山正湖→200種以上のハーブが咲く抱川ハーブアイランド（10万平米）→廃採石場を再活用した野外彫刻公園・抱川アートバレー（チョンジュ湖が見どころ）。","badges":["ソウル発","抱川","ハーブアイランド","アートバレー","自然＆アート"],"duration":"一日ツアー"},"zh":{"title":"抱川一日游：山亭湖、香草岛＆抱川艺术谷","description":"A relaxed seasonal day-trip from Seoul to Pocheon, the Gyeonggi countryside known for its lakes, herb gardens, and dramatic art-park landscapes. The route combines Sanjeong Lake''s mountain-circled waters, Herb Island''s Mediterranean-style gardens and evening lights, and Pocheon Art Valley''s monorail-accessed quarry observatory. Less crowded than Nami Island and built around photo-led calm rather than landmark sprint.","badges":["自然摄影之旅","季节精华","浪漫夜灯"],"duration":"10 hours"},"zh-TW":{"title":"抱川一日遊：山亭湖、香草島＆抱川藝術谷","description":"A relaxed seasonal day-trip from Seoul to Pocheon, the Gyeonggi countryside known for its lakes, herb gardens, and dramatic art-park landscapes. The route combines Sanjeong Lake''s mountain-circled waters, Herb Island''s Mediterranean-style gardens and evening lights, and Pocheon Art Valley''s monorail-accessed quarry observatory. Less crowded than Nami Island and built around photo-led calm rather than landmark sprint.","badges":["自然攝影之旅","季節精華","浪漫夜燈"],"duration":"10 hours"},"es":{"title":"Pocheon Day Trip: Sanjeong Lake, Herb Island & Pocheon Art Valley","description":"Excursión de un día desde Seúl a Pocheon, a ~1 hora al norte: el Lago Sanjeong (paisaje alpino de montaña a 380 m) → Herb Island de Pocheon (10 ha de jardines aromáticos, apodado el Provence de Corea, más de 100 especies) → Arte Valle de Pocheon (antigua cantera de granito reconvertida en parque escultórico con el lago Cheonju de color esmeralda). Tres escenas radicalmente distintas en un día.","badges":["Nature & Photo Trip","Seasonal Highlights","Romantic Evening Lights"],"duration":"10 hours"}}'::jsonb, updated_at = NOW() WHERE slug = 'pocheon-sanjeong-lake-herb-island-art-valley';
UPDATE tours SET translations = '{"ko":{"title":"서울 DMZ 프라이빗 투어: 제3땅굴+감악산 출렁다리","description":"임진각 평화공원, 제3땅굴(1978년 발견 북한 침투 터널), 도라전망대(판문점 방향 DMZ 조망), 감악산 출렁다리(220m 현수교)를 프라이빗으로 하루에. 여권 지참 필수. 월요일 미운행.","badges":["프라이빗 전세 투어","DMZ+출렁다리","호텔 픽업 포함"],"duration":"8–9 hours"},"ja":{"title":"ソウルDMZプライベートツアー：第3トンネル＆駒岳山レッドブリッジ","description":"韓国で最も重い歴史的スポットとフォトジェニックな山の吊り橋を組み合わせたプライベート日帰りツアー。午前は非武装地帯（臨津閣平和公園→第3浸透トンネル→都羅展望台）、午後は駒岳山の鮮やかな赤いサスペンションブリッジへ。パスポート必携。","badges":["プライベート","DMZ","第3トンネル","ソウル発","パスポート必須"],"duration":"一日ツアー"},"zh":{"title":"首尔DMZ私人行程：第三地道＆감악산悬索桥","description":"A private day-trip pairing Korea''s heaviest historical site with one of its most photogenic mountain bridges. Morning at the DMZ (Imjingak Peace Park, 3rd Infiltration Tunnel, Dora Observatory), then an afternoon walk across the 220-meter Gamaksan Red Suspension Bridge. Passport required for the DMZ portion.","badges":["私人包车游","非军事区＋悬索桥","饭店接送含括"],"duration":"8–9 hours"},"zh-TW":{"title":"首爾DMZ私人行程：第三地道＆감악산懸索橋","description":"A private day-trip pairing Korea''s heaviest historical site with one of its most photogenic mountain bridges. Morning at the DMZ (Imjingak Peace Park, 3rd Infiltration Tunnel, Dora Observatory), then an afternoon walk across the 220-meter Gamaksan Red Suspension Bridge. Passport required for the DMZ portion.","badges":["私人包車遊","非軍事區＋懸索橋","飯店接送含括"],"duration":"8–9 hours"},"es":{"title":"Seoul DMZ Private Tour: 3rd Tunnel + Gamaksan Suspension Bridge","description":"Tour privado al DMZ (Zona Desmilitarizada) desde Seúl con recogida en hotel: Parque de la Paz de Imjingak (Puente de la Libertad de 1953) → 3er Túnel de Infiltración (descubierto en 1978, a 44 km de Seúl, ⚠️ pasaporte obligatorio) → Observatorio Dora (punto de observación más septentrional de Corea del Sur) → Puente colgante rojo de Gamaksan (150 m sobre el barranco). Coche privado, recogida en hotel.","badges":["Private Tour","DMZ + Suspension Bridge","Hotel Pickup Included"],"duration":"8–9 hours"}}'::jsonb, updated_at = NOW() WHERE slug = 'seoul-dmz-private-3rd-tunnel-suspension-bridge';
UPDATE tours SET translations = '{"ko":{"title":"서울 프라이빗 투어: 남이섬·아침고요수목원·쁘띠프랑스","description":"남이섬(460,000㎡ 강 섬, 페리 도착), 아침고요수목원(한국 대표 사립 수목원), 쁘띠프랑스(프랑스 테마 문화 마을)를 프라이빗 차량으로 하루에. 전 입장료 포함.","badges":["프라이빗 전세 투어","한드 촬영지","커플·가족 추천"],"duration":"9–10 hours"},"ja":{"title":"ソウルプライベートツアー：南怡島・晨靜苑・プチフランス","description":"「冬のソナタ」のロケ地・南怡島の並木フェリー体験、22のテーマ庭園を持つ晨靜苑の花の散策、「星の王子さま」がテーマのプチフランスのコロニアル建築街を巡るソウル発プライベート日帰りツアー。ホテル送迎・全入場料込み。","badges":["プライベート","南怡島","晨靜苑","プチフランス","ソウル発"],"duration":"一日ツアー（プライベート）"},"zh":{"title":"首尔私人行程：南怡岛、晨静苑＆小法国村","description":"A private day trip from Seoul covering Nami Island''s tree-lined ferry experience, the Garden of Morning Calm''s themed garden walks, and the colorful Le Petit Prince village of Petite France. Hotel pickup, private vehicle, and a relaxed pace make this the comfort-led version of a classic Gapyeong loop.","badges":["私人包车游","韩剧拍摄地","情侣家庭适合"],"duration":"9–10 hours"},"zh-TW":{"title":"首爾私人行程：南怡島、晨靜苑＆小法國村","description":"A private day trip from Seoul covering Nami Island''s tree-lined ferry experience, the Garden of Morning Calm''s themed garden walks, and the colorful Le Petit Prince village of Petite France. Hotel pickup, private vehicle, and a relaxed pace make this the comfort-led version of a classic Gapyeong loop.","badges":["私人包車遊","韓劇拍攝地","情侶家庭適合"],"duration":"9–10 hours"},"es":{"title":"Tour Privado Seúl→Gapyeong: Isla Nami, Jardín de la Mañana Tranquila y Petite France","description":"Las tres experiencias más fotogénicas de Gapyeong en un día privado desde Seúl: Isla Nami (isla fluvial, ''Winter Sonata'', arboleda de metasecoya) → Jardín de la Mañana Tranquila (330.000 m², 22 jardines temáticos) → Petite France (aldea alsaciana con la mayor colección de ''El Principito'' de Asia). Coche privado, recogida en hotel, entradas incluidas.","badges":["Tour privado","Isla Nami","K-drama","Parejas y familias"],"duration":"Un día privado"}}'::jsonb, updated_at = NOW() WHERE slug = 'seoul-private-nami-morning-calm-petite-france';
UPDATE tours SET translations = '{"ko":{"title":"서울 출발 설악산·속초해변 일일 투어","description":"설악산국립공원(유네스코 생물권보전지역, 신흥사, 케이블카 선택), 속초관광수산시장(동해 해산물), 속초해변을 소그룹으로 하루에. 서울 왕복 차량 포함.","badges":["소그룹","자연 경관","절경","해변","수산시장","단풍","일일 투어"],"duration":"12 hours"},"ja":{"title":"雪岳山国立公園＆束草海岸日帰りツアー（ソウル発）","description":"韓国で最も愛される山岳国立公園と東海岸の港町・束草を巡るソウル発少人数日帰りツアー。雪岳山の花崗岩峰・渓谷・新興寺と青銅大仏（ケーブルカーで標高800mへ）に、束草の活きの良い海産物市場と白砂ビーチを組み合わせた14〜16時間の充実コース。","badges":["ソウル発","雪岳山","束草","国立公園","東海岸"],"duration":"一日ツアー（約14〜16時間）"},"zh":{"title":"首尔出发雪岳山国立公园＆束草海滩一日游","description":"A small-group day-trip from Seoul to Korea''s most-loved national park and the East Sea coastal city of Sokcho. The route pairs Seoraksan''s granite peaks, valleys, and Buddhist heritage with the seafood market and beach of Sokcho — a mountain-and-ocean combination only the east coast offers. 12 hours with English-speaking guide and round-trip transport.","badges":["小团体","自然风光","绝美景色","海滩","海鲜市场","Autumn Foliage","一日游"],"duration":"12 hours"},"zh-TW":{"title":"首爾出發雪嶽山國立公園＆束草海灘一日遊","description":"A small-group day-trip from Seoul to Korea''s most-loved national park and the East Sea coastal city of Sokcho. The route pairs Seoraksan''s granite peaks, valleys, and Buddhist heritage with the seafood market and beach of Sokcho — a mountain-and-ocean combination only the east coast offers. 12 hours with English-speaking guide and round-trip transport.","badges":["小團體","自然風光","絕美景色","海灘","海鮮市場","Autumn Foliage","一日遊"],"duration":"12 hours"},"es":{"title":"Tour Seúl→Seoraksan: Parque Nacional UNESCO, Mercado de Sokcho y Playa","description":"Excursión intensa de un día desde Seúl al Parque Nacional Seoraksan (Reserva de la Biosfera UNESCO, las montañas de granito más espectaculares de Corea) y la ciudad costera de Sokcho: cablecar hasta los 800 m + Templo Sinheungsa y Buda de Bronce → Mercado Pesquero de Sokcho (marisco de primera mano) → Playa de Sokcho (Mar del Este, arena blanca). 14-16 horas de ida y vuelta. Solo para quien quiera una jornada intensa.","badges":["Grupo pequeño","Naturaleza","Seoraksan UNESCO","Playa","Mercado marisco","Follaje otoñal","Excursión un día"],"duration":"14-16 horas (jornada intensa)"}}'::jsonb, updated_at = NOW() WHERE slug = 'seoul-seoraksan-national-park-sokcho-beach-day-trip';
UPDATE tours SET translations = '{"ko":{"title":"서울 교외 프라이빗 전세 차량 투어 · 10시간","description":"유자격 드라이버 가이드와 에어컨 프라이빗 차량으로 서울 근교 10시간 맞춤 투어. 가평 자연·문화 루프(남이섬·아침고요 등), DMZ+파주 코스, 에버랜드+민속촌, 또는 완전 커스텀 선택 가능.","badges":["프라이빗 전세 투어","완전 맞춤형","서울 호텔 무료 픽업"],"duration":"10 hours"},"ja":{"title":"ソウル近郊プライベートカーチャーターツアー（10時間カスタム）","description":"3つの推薦ルートから選べる、または完全カスタムで自分だけのソウル近郊の一日を設計できる10時間プライベートカーチャーター。加平の自然ループ（南怡島・晨靜苑・プチフランス）、DMZ歴史ルート（臨津閣・第3トンネル・坡州）、エバーランド＋韓国民俗村から選択可。","badges":["プライベート","ソウル近郊","カスタムルート","エバーランド","DMZ"],"duration":"10時間"},"zh":{"title":"首尔市区或近郊私人包车10小时行程","description":"A premium 10-hour private car charter that lets you build your own Seoul-area day. Choose one of three recommended routes—Nami Island + Morning Calm + Petite France + Gangchon Railbike, DMZ + Paju Outlet, or Everland + Korean Folk Village—or send your own itinerary. Free hotel pickup is included for Seoul downtown stays.","badges":["私人包车游","完全自订行程","免费首尔饭店接送"],"duration":"10 hours"},"zh-TW":{"title":"首爾市區或近郊私人包車10小時行程","description":"A premium 10-hour private car charter that lets you build your own Seoul-area day. Choose one of three recommended routes—Nami Island + Morning Calm + Petite France + Gangchon Railbike, DMZ + Paju Outlet, or Everland + Korean Folk Village—or send your own itinerary. Free hotel pickup is included for Seoul downtown stays.","badges":["私人包車遊","完全自訂行程","免費首爾飯店接送"],"duration":"10 hours"},"es":{"title":"Chárter Privado 10 Horas desde Seúl: 3 Rutas Recomendadas o Itinerario Totalmente Personalizado","description":"Coche privado con guía-conductor certificado por 10 horas desde Seúl — elija entre tres rutas recomendadas: Ruta 1 (Gapyeong: Nami + Achimsogwon + Petite France), Ruta 2 (DMZ: 3er Túnel + Observatorio Dora + Paju Outlets) o Ruta 3 (Yongin: Everland + Pueblo Folclórico Coreano) — o diseñe su propio itinerario completamente a medida. Recogida gratuita en hotel de Seúl. 10 horas de coche privado para solo su grupo.","badges":["Tour privado","Totalmente personalizable","Recogida gratuita en hotel"],"duration":"10 horas (chárter privado)"}}'::jsonb, updated_at = NOW() WHERE slug = 'seoul-suburbs-private-chartered-car-10hr';
UPDATE tours SET translations = '{"ko":{"title":"수원화성·한국민속촌·스타필드 소그룹 투어","description":"수원화성(유네스코 세계문화유산), 화성행궁(한국 최대 행궁), 한국민속촌(용인, 한국 최초·최대 야외 민속박물관), 스타필드 수원 별마당도서관을 소그룹으로 하루에 돌아봅니다. 전 입장료 포함, 공인 가이드.","badges":["소그룹","문화 체험","유네스코","역사 유적","도서관","민속마을","일일 투어"],"duration":"10 hours"},"ja":{"title":"水原華城・民俗村・スターフィールド図書館日帰りツアー","description":"ソウルから日帰りで京畿道の4つの対照的な側面を体験：UNESCO世界遺産の水原華城の城壁ウォーク・朝鮮時代の離宮・韓国最初の野外民俗博物館（韓国民俗村）・22mの書架が連なるスターフィールド・スウォン図書館。少人数英語ガイド付き。","badges":["少人数","水原","UNESCO","民俗村","ソウル発"],"duration":"10時間"},"zh":{"title":"水原华城、韩国民俗村＆星空图书馆一日游","description":"A small-group cultural day-trip from Seoul to Gyeonggi Province covering four contrasting sides of Korean heritage and modern life: the UNESCO-listed Suwon Hwaseong Fortress (18th-century walls and gates), the restored Hwaseong Haenggung Palace with its Joseon-era reenactments, the immersive open-air Korean Folk Village in Yongin, and the dramatic four-floor Starfield Library Suwon. 10 hours with included transport and admissions.","badges":["小团体","文化体验","世界遗产","历史遗迹","图书馆","民俗村","一日游"],"duration":"10 hours"},"zh-TW":{"title":"水原華城、韓國民俗村＆星空圖書館一日遊","description":"A small-group cultural day-trip from Seoul to Gyeonggi Province covering four contrasting sides of Korean heritage and modern life: the UNESCO-listed Suwon Hwaseong Fortress (18th-century walls and gates), the restored Hwaseong Haenggung Palace with its Joseon-era reenactments, the immersive open-air Korean Folk Village in Yongin, and the dramatic four-floor Starfield Library Suwon. 10 hours with included transport and admissions.","badges":["小團體","文化體驗","世界遺產","歷史遺跡","圖書館","民俗村","一日遊"],"duration":"10 hours"},"es":{"title":"Tour Suwon y Yongin: Fortaleza UNESCO, Pueblo Folclórico y Biblioteca Starfield","description":"Excursión de un día en grupo pequeño desde Seúl explorando cuatro contrastes de la provincia de Gyeonggi: paseo por las murallas de la Fortaleza Hwaseong (Patrimonio UNESCO 1997) → Palacio Haenggung (el mayor palacio de campaña real de Corea) → Pueblo Folclórico Coreano de Yongin (el primer museo al aire libre del país) → Biblioteca Starfield de Suwon (atrio de 22 m, el espacio más fotografiado del nuevo Starfield). 10 horas, grupo pequeño.","badges":["Grupo pequeño","UNESCO","Pueblo Folclórico","Biblioteca Starfield","Desde Seúl"],"duration":"10 horas"}}'::jsonb, updated_at = NOW() WHERE slug = 'seoul-suwon-hwaseong-folk-village-starfield-library';
UPDATE tours SET translations = '{"ko":{"title":"수원화성·광명동굴·스타필드 소그룹 투어","description":"수원화성(유네스코 세계문화유산), 화성행궁, 스타필드 수원 별마당도서관, 광명동굴(1912년 금광 폐갱 개조 LED 테마파크)을 소그룹으로 하루에 돌아봅니다. 월요일 미운행. 전 입장료 포함.","badges":["소그룹","문화 체험","유네스코","용암 동굴","도서관","쇼핑","일일 투어"],"duration":"9 hours"},"ja":{"title":"水原華城・光明洞窟・スターフィールド図書館日帰りツアー","description":"ソウル発少人数日帰りツアーで京畿道の4つの対照的な側面を体験：UNESCO登録の水原华城（18世紀の城壁と华城行宮）→水原南門市場での昼食→スターフィールド・スウォン図書館（22m吹き抜け）→光明洞窟（旧金銀鉱山の地下観光施設）。月曜日運休（光明洞窟定休日）。","badges":["少人数","水原","UNESCO","光明洞窟","ソウル発"],"duration":"9時間"},"zh":{"title":"水原华城、光明洞窟＆星空图书馆一日游","description":"A small-group cultural day-trip from Seoul covering four contrasting sides of Gyeonggi Province: the UNESCO-listed Suwon Hwaseong Fortress with its 18th-century walls and Haenggung Palace, the dramatic LED-lit underground theme park inside Gwangmyeong Cave (a former Japanese-era gold mine), the four-floor Starfield Library Suwon, and the 1,000-year-old Nammun traditional market for street food. 9 hours with included transport and admissions.","badges":["小团体","文化体验","世界遗产","熔岩洞穴","图书馆","购物","一日游"],"duration":"9 hours"},"zh-TW":{"title":"水原華城、光明洞窟＆星空圖書館一日遊","description":"A small-group cultural day-trip from Seoul covering four contrasting sides of Gyeonggi Province: the UNESCO-listed Suwon Hwaseong Fortress with its 18th-century walls and Haenggung Palace, the dramatic LED-lit underground theme park inside Gwangmyeong Cave (a former Japanese-era gold mine), the four-floor Starfield Library Suwon, and the 1,000-year-old Nammun traditional market for street food. 9 hours with included transport and admissions.","badges":["小團體","文化體驗","世界遺產","熔岩洞穴","圖書館","購物","一日遊"],"duration":"9 hours"},"es":{"title":"Tour Suwon: Fortaleza UNESCO, Cueva Gwangmyeong y Biblioteca Starfield","description":"Excursión de un día en grupo pequeño desde Seúl: Fortaleza Hwaseong (Patrimonio UNESCO) → Palacio Haenggung → almuerzo en el Mercado Nammun de Suwon → Biblioteca Starfield (atrio de 22 m) → Cueva Gwangmyeong (antigua mina de oro, plata y cobre del período colonial japonés convertida en galería de arte subterránea). 4 experiencias radicalmente distintas en un día. Nota: cerrado los lunes (Cueva Gwangmyeong cierra los lunes).","badges":["Grupo pequeño","UNESCO","Cueva (antigua mina)","Biblioteca Starfield","Desde Seúl","Cerrado lunes"],"duration":"9 horas (no disponible lunes)"}}'::jsonb, updated_at = NOW() WHERE slug = 'seoul-suwon-hwaseong-gwangmyeong-cave-starfield-library';
UPDATE tours SET translations = '{"ko":{"title":"수원화성·와우정사·스타필드 소그룹 투어","description":"수원화성(유네스코 세계문화유산), 화성행궁, 스타필드 수원 별마당도서관, 와우정사(용인 산속 국제불교 사찰)를 소그룹으로 하루에 돌아봅니다. 전 입장료 포함, 공인 가이드, 4.9/5 평점.","badges":["유네스코 문화유산","역사유적+현대 일일 투어","입장료 포함"],"duration":"9–10 hours"},"ja":{"title":"水原華城・臥牛精舍・スターフィールド図書館日帰りツアー","description":"ソウル発少人数日帰りツアーで韓国の3つの対照的な側面を体験：UNESCO登録の水原华城（18世紀の軍事建築）→スターフィールド・スウォン図書館（22m吹き抜けの現代建築）→臥牛精舍（1970年創建、汎アジア仏教様式を融合した現代寺院・約3,000体の仏像）。","badges":["少人数","水原","UNESCO","臥牛精舍","ソウル発"],"duration":"9〜10時間"},"zh":{"title":"水原华城＋와우정사＋星空图书馆文化遗产一日游","description":"A small-group day-trip from Seoul covering three contrasting sides of Korea: the UNESCO-listed Suwon Hwaseong Fortress (18th-century military architecture), the photogenic Starfield Suwon Library (contemporary cultural icon), and Waujeongsa Temple in Yongin (giant outdoor Buddha and stone bell). Strong heritage value with included transport and admission.","badges":["世界文化遗产","历史遗迹＋现代一日游","门票已包含"],"duration":"9–10 hours"},"zh-TW":{"title":"水原華城＋와우정사＋星空圖書館文化遺產一日遊","description":"A small-group day-trip from Seoul covering three contrasting sides of Korea: the UNESCO-listed Suwon Hwaseong Fortress (18th-century military architecture), the photogenic Starfield Suwon Library (contemporary cultural icon), and Waujeongsa Temple in Yongin (giant outdoor Buddha and stone bell). Strong heritage value with included transport and admission.","badges":["世界文化遺產","歷史遺跡＋現代一日遊","門票已包含"],"duration":"9–10 hours"},"es":{"title":"Tour Suwon: Fortaleza Hwaseong, Biblioteca Starfield y Templo Waujeongsa","description":"Tres caras radicalmente distintas de Corea en un día desde Seúl: Fortaleza Hwaseong de Suwon (Patrimonio UNESCO 1997, murallas del siglo XVIII) → Biblioteca Starfield de Suwon (atrio de libros de 22 m, abierta en 2024) → Templo Waujeongsa en Yongin (fundado en 1970, ~3.000 estatuas de estilos budistas pan-asiáticos, entrada gratuita). Recogida en Seúl, entradas incluidas, todo el año disponible.","badges":["Patrimonio UNESCO","Patrimonio + Modernidad","Entrada incluida"],"duration":"Un día completo"}}'::jsonb, updated_at = NOW() WHERE slug = 'seoul-suwon-hwaseong-waujeongsa-starfield';
UPDATE tours SET translations = '{"ko":{"title":"제주 서남부 소그룹 투어: 한라산·오설록·애월","description":"어승생악(한라산 기생화산) 트레일을 시작으로 주상절리, 천제연폭포, 오설록 티뮤지엄을 거쳐 애월 한담 해안산책로 카페거리에서 마무리하는 제주 서남부 소그룹 투어입니다. 공인 가이드, 4.8/5 평점.","badges":["제주 첫 방문 최고 선택","제주 서남부"],"duration":"8 hours"},"ja":{"title":"済州南西部少人数ツアー：漢拏山・O''sulloc・涯月","description":"漢拏山（御乗生岳）の短いトレイルハイク、火山海岸の柱状節理、天帝淵の滝、韓国最大の茶畑、そして涯月のカフェ通りでリラックスしたフィナーレ。済州南西部のエッセンスをバランスよく一日で体験できる少人数ツアーです。","badges":["少人数","済州","済州南西部","UNESCO","カフェ文化","自然"],"duration":"8時間"},"zh":{"title":"济州西南小团体一日游：汉拏山＆오설록＆爱月","description":"A well-balanced Jeju southwest route linking a short Hallasan walk, volcanic coastline, Cheonjeyeon Waterfall, O’Sulloc tea fields, and Aewol Cafe Street.","badges":["济州初访首选","济州西南"],"duration":"8 hours"},"zh-TW":{"title":"濟州西南小團體一日遊：漢拏山＆오설록＆愛月","description":"A well-balanced Jeju southwest route linking a short Hallasan walk, volcanic coastline, Cheonjeyeon Waterfall, O’Sulloc tea fields, and Aewol Cafe Street.","badges":["濟州初訪首選","濟州西南"],"duration":"8 hours"},"es":{"title":"Tour Jeju Suroeste: Hallasan, Acantilados, Té y Cafés Aewol","description":"La ruta ideal para una primera visita al suroeste de Jeju: senderismo Eoseungsaengak en el Hallasan (Patrimonio UNESCO), Acantilado Jusangjeolli de basalto hexagonal (Geoparque UNESCO), almuerzo en Jungmun, Cascadas Cheonjeyeon, campos de té Osulloc y un cierre relajado en los cafés costeros de Aewol (Paseo Handam). Recogida en hotel de Jeju Ciudad, entradas incluidas.","badges":["Ideal para primera visita a Jeju","Jeju Suroeste","Recogida en hotel incluida"],"duration":"Un día (recogida en hotel)"}}'::jsonb, updated_at = NOW() WHERE slug = 'southwest-hallasan-osulloc-aewol';
COMMIT;
